// src/components/grid/Grid.ts
export class DataGrid extends HTMLElement {
  // Core logic only (2KB)
  render() { ... }
}

// src/traits/Sortable.ts
export interface SortableTrait {
  sortBy(dir: 'asc' | 'desc'): void;
}

// The Loader: runtime logic + compile-time type assertion
export function useSortable(grid: DataGrid): asserts grid is DataGrid & SortableTrait {
  if (!grid.hasAttribute('sortable')) {
    grid.setAttribute('sortable', ''); // 1. Runtime: Trigger initialization
    applySortableMixin(grid);          // 2. Logic: Mixin the methods
  }
}

function applySortableMixin(grid: DataGrid) {
  const host = grid as any;

  // Implement the interface
  host.sortBy = (dir: 'asc' | 'desc') => {
    console.log(`Sorting ${dir}...`);
    // Access public properties of the grid
    grid.items.sort((a, b) => dir === 'asc' ? a - b : b - a);
    grid.render();
  };
}

const grid = new DataGrid();

// ❌ Error: Property 'sortBy' does not exist on 'DataGrid'
// grid.sortBy('asc'); 

// ✅ Load the Trait (Logic + Types)
useSortable(grid);

// ✅ Success: TypeScript now knows 'grid' has 'sortBy'
grid.sortBy('asc');

// 1. Attribute Trigger (Template Analysis)
// <data-grid sortable />  ➡️  useSortable(grid)

// 2. Method Trigger (Code Analysis)
// grid.sortBy('asc')      ➡️  useSortable(grid); grid.sortBy('asc')
